class Solution(object):
    def minExtraChar(self, s, dictionary):
        n = len(s)
        word_set = set(dictionary)
        dp = [0] * (n + 1)
        for i in range(1, n + 1):
            dp[i] = dp[i-1] + 1  # s[i-1] is extra
            for j in range(i):
                if s[j:i] in word_set:
                    dp[i] = min(dp[i], dp[j])
        return dp[n]
